                {urlError}
              </p>
            )}
            {urlValid && youtubeUrl && (
              <div className="mt-4 rounded-xl overflow-hidden border border-white/10 aspect-video relative group">
                <img
                  src={getYouTubeThumbnail(extractYouTubeId(youtubeUrl) || "", "high")}
                  alt="YouTube preview"
                  className="w-full h-full object-cover"
                />
                <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                  <div className="w-14 h-14 rounded-full bg-white/20 backdrop-blur-sm flex items-center justify-center border border-white/30">
                    <svg width="20" height="20" viewBox="0 0 24 24" fill="white">
                      <path d="M8 5v14l11-7z"/>
                    </svg>
                  </div>
                </div>
                <div className="absolute bottom-2 left-2 text-xs text-white/80 bg-black/50 px-2 py-1 rounded-md backdrop-blur-sm">
                  Γ£ô Video detected
                </div>
              </div>
            )}
          </div>
        ) : (
          <div
            onDragOver={(e) => { e.preventDefault(); setDragOver(true); }}
            onDragLeave={() => setDragOver(false)}
            onDrop={handleFileDrop}
            onClick={() => fileInputRef.current?.click()}
            className={`relative border-2 border-dashed rounded-2xl p-10 text-center cursor-pointer transition-all duration-300 ${
              dragOver
                ? "border-violet-500 bg-violet-500/10 scale-[1.01]"
                : uploadedFile
                ? "border-emerald-500/50 bg-emerald-500/5"
                : "border-white/15 hover:border-violet-500/40 hover:bg-white/[0.02]"
            }`}
          >
            <input
              ref={fileInputRef}
              type="file"
              accept="video/*"
              className="hidden"
              onChange={handleFileSelect}
            />
            {uploadedFile ? (
              <div className="flex flex-col items-center gap-3">
                <div className="w-14 h-14 rounded-2xl bg-emerald-500/20 flex items-center justify-center">
                  <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="#34d399" strokeWidth="2">
                    <path d="M20 6L9 17l-5-5"/>
                  </svg>
                </div>
                <div>
                  <p className="font-semibold text-white">{uploadedFile.name}</p>
                  <p className="text-sm text-[var(--text-muted)] mt-1">
                    {(uploadedFile.size / (1024 * 1024)).toFixed(1)} MB ΓÇó Click to change
                  </p>
                </div>
              </div>
            ) : (
              <div className="flex flex-col items-center gap-4">
                <div className="w-16 h-16 rounded-2xl bg-white/5 border border-white/10 flex items-center justify-center">
                  <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="var(--text-muted)" strokeWidth="1.5">
                    <rect x="2" y="3" width="20" height="14" rx="2" ry="2"/>
                    <path d="M8 21h8M12 17v4"/>
                  </svg>
                </div>
                <div>
                  <p className="font-medium text-[var(--text-primary)]">Drop your video here</p>
                  <p className="text-sm text-[var(--text-muted)] mt-1">or click to browse ┬╖ MP4, MOV, WebM</p>
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

